import numpy as npimport timefrom reeds_shepp_path_planning import reeds_shepp_path_planning,remove_duplicates,vis_wayp,remove_same_neighborfrom comb_planning_minE import select_points_with_equal_intervalsfrom mist_new import mist_generatorfrom test_minE import wayp_minE_debug,wayp_minEfrom turning_points import check_turning_points,find_turning_pointsimport matplotlib.pyplot as pltfrom scipy.optimize import curve_fitdef output_key_var(start_x,start_y,start_yaw,end_x,end_y,deg,T = 1):    curvature = 1    step_size = 0.3 # 0.05            end_yaw = np.deg2rad(deg)    xs, ys, yaws, modes, lengths = reeds_shepp_path_planning(start_x, start_y,                                                             start_yaw, end_x,                                                             end_y, end_yaw,                                                             curvature,                                                             step_size)    uxs,uys = remove_same_neighbor(xs,ys)        turning_points = find_turning_points(uxs,uys)        check = check_turning_points(uxs,uys)  # if true, then same position        num_points_to_select = 4  # Change this to select a different number of points        s_xs = select_points_with_equal_intervals(uxs, num_points_to_select)    s_ys = select_points_with_equal_intervals(uys, num_points_to_select)    waypts_ori = np.array([s_xs,s_ys])        v0 = np.array([0,0])    a0 = np.array([0,0])    ve = np.array([0,0])    ae = np.array([0,0])      myMistGen = mist_generator()    minE1,xxs,yys = wayp_minE_debug(myMistGen,waypts_ori,v0,a0,ve,ae,T)        # vis_wayp(uxs,uys)    # vis_wayp(xxs,yys)    return check, deg,minE1def polynomial_fit_param(degs,minEs,vis=False,if_save=True):    order = 5    coefficients = np.polyfit(degs, minEs, order)    poly_fit = np.poly1d(coefficients)    x_fit = np.linspace(min(degs), max(degs), 100)    y_fit = poly_fit(x_fit)        # plot it    if vis == True:        plt.scatter(degs, minEs, label='original')        plt.plot(x_fit, y_fit, color='red', label='polynomial_fit')        if if_save==True:        npy_name = "/Users/zhaoliang/Documents/Smart_intersection/CooperFuse/mistgen/ploy_param/poly_p_T01.npy"        np.save(npy_name, coefficients)            return coefficientsdef polynomial_fit(deg,coefficients):        poly_fit = np.poly1d(coefficients)    y_fit = poly_fit(deg)        return y_fitdef load_saved_data():    # Specify the path to the .npy file    npy_name = "/Users/zhaoliang/Documents/Smart_intersection/CooperFuse/mistgen/ploy_param/poly_p.npy"        # Load the data from the .npy file    loaded_data = np.load(npy_name)         return loaded_data    def test1():    start_x = 5.0  # [m]    start_y = 5.0  # [m]    start_yaw = np.deg2rad(0.0)  # [rad]    end_x = 5.0  # [m]    end_y = 5.0  # [m]    end_yaw = np.deg2rad(-40.0)  # [rad]    curvature = 1    step_size = 0.3 # 0.05    # start time    start_time = time.time()    xs, ys, yaws, modes, lengths = reeds_shepp_path_planning(start_x, start_y,                                                             start_yaw, end_x,                                                             end_y, end_yaw,                                                             curvature,                                                             step_size)        num_points_to_select = 4  # Change this to select a different number of points    s_xs = select_points_with_equal_intervals(xs, num_points_to_select)    s_ys = select_points_with_equal_intervals(ys, num_points_to_select)    # end time    end_time = time.time()    t_dur0 = end_time - start_time        # "minimum snap trajectory generation and control for quadrotors"    ax1 = [0.0, 5.0,9.0]    ay1 = [0.0, 0.0,1.0]    waypts_ori = np.array([ax1,ay1])    waypts_ori1 = np.array([s_xs,s_ys])    T = 10    v0 = np.array([0,0])    a0 = np.array([0,0])    ve = np.array([0,0])    ae = np.array([0,0])        # start_t = time.time()    myMistGen = mist_generator()    minE1 = wayp_minE(myMistGen,waypts_ori1,v0,a0,ve,ae,T)    # end_t1 =  time.time()    # t_dur1 = end_t1 - start_t    # t_fin = end_t1 - start_time     def test2():    start_x = 5.0  # [m]    start_y = 5.0  # [m]    start_yaw = np.deg2rad(0.0)  # [rad]    end_x = 5.0  # [m]    end_y = 5.0  # [m]        deg = 20.0    # end_yaw = np.deg2rad(deg)  # [rad] <-20        checks = []    degs = []    minEs = []        while deg<=90:            check, deg, minE1 = output_key_var(start_x,start_y,start_yaw,end_x,end_y,deg,T=0.1)        checks.append(check)        degs.append(deg)        minEs.append(minE1[0][0])        deg += 5                degs = [0.0] + degs    minEs = [0.0] + minEs    plt.figure()    plt.plot(degs,minEs)        coefficients = polynomial_fit_param(degs,minEs,True)        my_deg = 0.0    y_fit_m = polynomial_fit(my_deg,coefficients)    poly_fit = np.poly1d(coefficients)    x_fit = np.linspace(min(degs), max(degs), 100)    y_fit = poly_fit(x_fit)        plt.plot(x_fit,y_fit)def test3():    name = npy_name = "/Users/zhaoliang/Documents/Smart_intersection/CooperFuse/mistgen/ploy_param/poly_p_T01.npy"    coefficients = np.load(npy_name)    my_deg = 0.0    y_fit_m = polynomial_fit(my_deg,coefficients)        poly_fit = np.poly1d(coefficients)    x_fit = np.linspace(0, 90, 100)    y_fit = poly_fit(x_fit)    if __name__ == '__main__':    name = npy_name = "/Users/zhaoliang/Documents/Smart_intersection/CooperFuse/mistgen/ploy_param/poly_p_T01.npy"    coefficients = np.load(npy_name)    my_deg = 0.0    y_fit_m = polynomial_fit(my_deg,coefficients)        poly_fit = np.poly1d(coefficients)    x_fit = np.linspace(0, 90, 100)    y_fit = poly_fit(x_fit)                                        